pub fn extract_bearer_token(auth_header: &str) -> Result<&str, JwtVerifyError> {
    let value = auth_header.trim();
    if value.is_empty() {
        return Err(JwtVerifyError::MissingAuthorizationHeader);
    }

    let mut parts = value.splitn(2, ' ');
    let scheme = parts.next().unwrap_or_default();
    let token = parts.next().unwrap_or_default();

    if !scheme.eq_ignore_ascii_case("Bearer") {
        return Err(JwtVerifyError::InvalidAuthorizationHeader);
    }

    let token = token.trim();
    if token.is_empty() {
        return Err(JwtVerifyError::EmptyBearerToken);
    }

    Ok(token)
}

